file.content:
        _data[indx] = dval
        if mval is not nomask:
            _mask = self._mask = make_mask_none(self.shape, _dtype)
            _mask[indx] = mval
    elif not self._hardmask:
        # Set the data, then the mask
        if (isinstance(indx, masked_array) and
                not isinstance(value, masked_array)):
            _data[indx.data] = dval
        else:
            _data[indx] = dval
            _mask[indx] = mval
    elif hasattr(indx, 'dtype') and (indx.dtype == MaskType):
        indx = indx * umath.logical_not(_mask)
        _data[indx] = dval
    else:
        if _dtype.names is not None:
            err_msg = "Flexible 'hard' masks are not yet supported."
            raise NotImplementedError(err_msg)
        mindx = mask_or(_mask[indx], mval, copy=True)
        dindx = self._data[indx]
        if dindx.size > 1:
            np.copyto(dindx, dval, where=~mindx)
        elif mindx is nomask:
            dindx = dval
        _data[indx] = dindx
        _mask[indx] = mindx
    return

def _set_dtype(self, dtype):
    super()._set_dtype(dtype)
    if self._mask is not nomask:
        self._mask = self._mask.view(make_mask_descr(dtype), ndarray)
        try:
            self._mask = self._mask.reshape(self.shape)
        except (AttributeError, TypeError):
            pass

# Define so that we can overwrite the setter.
@property
def dtype(self):
    return super().dtype

@dtype.setter
def dtype(self, dtype):
    # DEPRECATED 2026-02-06, NumPy 2.5
    warnings.warn(
        "Setting the dtype on a MaskedArray has been deprecated in "
        "NumPy 2.5.\nInstead of changing the dtype on an array x, "
        "create a new array with x.view(new_dtype)",
        DeprecationWarning, stacklevel=2)
    self._set_dtype(dtype)

@property
def shape(self):
    return super().shape

@shape.setter
def shape(self, shape):
    super(MaskedArray, type(self)).shape.__set__(self, shape)
    # Cannot use self._mask, since it may not (yet) exist when a
    # masked matrix sets the shape.
    if getmask(self) is not nomask:
        self._mask = self._mask.reshape(self.shape)

